#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>
#include <fcntl.h>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        // Fork failed
        perror("fork failed");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child Process: PID = %d\n", getpid());

        // System call for file creation
        int fd = creat("test.txt", 0644);
        if (fd < 0) {
            perror("file creation failed");
            _exit(1);
        }

        char buffer[] = "Hello from child process!\n";
        write(fd, buffer, sizeof(buffer));
        close(fd);

        _exit(0);
    }
    else {
        // Parent process
        printf("Parent Process: PID = %d, Child PID = %d\n", getpid(), pid);

        // Wait for child to complete (system call)
        int status;
        waitpid(pid, &status, 0);

        printf("Child process completed with status: %d\n", WEXITSTATUS(status));
    }

    return 0;
}
